<?php
require_once dirname(__DIR__) . '/includes/cms.php';$pdo=obtenerConexion();$claves=['nombre_sitio'=>'Nombre del sitio','correo'=>'Correo','telefono'=>'Teléfono','direccion'=>'Dirección','facebook'=>'Facebook','instagram'=>'Instagram','whatsapp'=>'WhatsApp'];$config=obtenerConfiguracionSitio();$errores=[];
if($_SERVER['REQUEST_METHOD']==='POST'){if(!validarTokenCsrf($_POST['csrf_token']??null))$errores[]='Token CSRF inválido.';$valores=[];foreach($claves as $clave=>$label)$valores[$clave]=trim((string)($_POST[$clave]??''));if($valores['nombre_sitio']==='')$errores[]='El nombre del sitio es obligatorio.';if($valores['correo']!==''&&!filter_var($valores['correo'],FILTER_VALIDATE_EMAIL))$errores[]='El correo no es válido.';foreach(['facebook','instagram','whatsapp'] as $clave)if(!cmsUrlValida($valores[$clave]))$errores[]="$claves[$clave] contiene una URL inválida.";
 $logo=$config['logo']??'img/atenea-logo.png';$favicon=$config['favicon']??'img/atenea-logo.png';try{$nuevoLogo=cmsSubirImagen('logo');if($nuevoLogo)$logo=$nuevoLogo;$nuevoFav=cmsSubirImagen('favicon');if($nuevoFav)$favicon=$nuevoFav;}catch(RuntimeException $e){$errores[]=$e->getMessage();}
 if(!$errores){try{$pdo->beginTransaction();$q=$pdo->prepare('INSERT INTO configuracion_sitio(clave,valor,tipo) VALUES(:clave,:valor,:tipo) ON DUPLICATE KEY UPDATE valor=VALUES(valor),tipo=VALUES(tipo)');foreach($valores as $clave=>$valor)$q->execute(['clave'=>$clave,'valor'=>$valor,'tipo'=>$clave==='correo'?'email':($clave==='telefono'?'telefono':(in_array($clave,['facebook','instagram','whatsapp'],true)?'url':'texto'))]);$q->execute(['clave'=>'logo','valor'=>$logo,'tipo'=>'imagen']);$q->execute(['clave'=>'favicon','valor'=>$favicon,'tipo'=>'imagen']);$pdo->commit();if($nuevoLogo??false)cmsEliminarImagenSiNoSeUsa($config['logo']??null);if($nuevoFav??false)cmsEliminarImagenSiNoSeUsa($config['favicon']??null);cmsFlash('exito','Configuración guardada.');header('Location: index.php');exit;}catch(Throwable $e){if($pdo->inTransaction())$pdo->rollBack();error_log($e->getMessage());$errores[]='No fue posible guardar la configuración.';}}$config=array_merge($config,$valores,['logo'=>$logo,'favicon'=>$favicon]);}
cmsCabecera('Configuración general','configuracion/index.php');?><?php foreach($errores as $e):?><div class="alert alert-danger"><?=atenea_e($e)?></div><?php endforeach;?><form method="post" enctype="multipart/form-data" class="card card-rounded"><div class="card-header bg-white"><h2 class="card-title mb-1">Información institucional</h2><p class="text-muted mb-0">Actualiza la identidad y los datos de contacto del sitio.</p></div><div class="card-body row g-3"><input type="hidden" name="csrf_token" value="<?=atenea_e(obtenerTokenCsrf())?>"><?php foreach($claves as $clave=>$label):?><div class="col-md-6"><label class="form-label"><?=atenea_e($label)?></label><input class="form-control" name="<?=$clave?>" maxlength="500" value="<?=atenea_e($config[$clave]??'')?>" <?=$clave==='nombre_sitio'?'required':''?>></div><?php endforeach;?><div class="col-md-6"><label class="form-label">Logo</label><input class="form-control" type="file" name="logo" accept=".jpg,.jpeg,.png,.webp"><?php if(!empty($config['logo'])):?><img class="preview-img mt-2" src="<?=rutaImagenContenido($config['logo'],'img/atenea-logo.png')?>" alt="Logo actual"><?php endif;?></div><div class="col-md-6"><label class="form-label">Favicon</label><input class="form-control" type="file" name="favicon" accept=".jpg,.jpeg,.png,.webp"><?php if(!empty($config['favicon'])):?><img class="preview-img mt-2" src="<?=rutaImagenContenido($config['favicon'],'img/atenea-logo.png')?>" alt="Favicon actual"><?php endif;?></div><div class="col-12"><a class="btn btn-light" href="<?=atenea_url('src/dashboard/index.php')?>"><i class="mdi mdi-arrow-left me-1"></i>Volver</a> <a class="btn btn-outline-secondary" href="<?=atenea_url('src/dashboard/index.php')?>">Cancelar</a> <button class="btn btn-primary text-white"><i class="mdi mdi-content-save me-1"></i>Guardar cambios</button></div></div></form><?php cmsPie();?>
